use alloy::sol;

sol! {
    /**
     * @notice Quotes output for Uniswap V3 pool (exact input single).
     * @dev Uses pool.swap() and reverts in callback with amountOut.
     */
    #[sol(rpc, bytecode="")]
    contract UniswapV3QuoteSingle {
        error AmountOut(uint256 amountOut);
        error InsufficientLiquidity();
        error PartialFill(uint256 amountOut, uint256 amountInConsumed);

        constructor(address pool, address tokenIn, uint256 amountIn, uint256 protocolFeeBps);
    }
}
